[Console]::OutputEncoding = [System.Text.Encoding]::UTF8
Add-Type -AssemblyName System.Data
$filePath = "C:\Users\Administrator\Desktop\JX1 PE M대응 RLPSU 진단사양서_수정 1.xlsx"
$connStr = "Provider=Microsoft.ACE.OLEDB.12.0;Data Source=`"$filePath`";Extended Properties=`"Excel 12.0 Xml;HDR=NO;IMEX=1`""
$conn = New-Object System.Data.OleDb.OleDbConnection($connStr)
$conn.Open()

# IOCtrl 시트 전체 (히터 관련 상세)
Write-Output "=========================================="
Write-Output "SHEET: IOCtrl_시트 - 전체 내용"
Write-Output "=========================================="
$cmd = $conn.CreateCommand()
$cmd.CommandText = "SELECT * FROM [IOCtrl_시트$]"
$reader = $cmd.ExecuteReader()
$rowNum = 0
while ($reader.Read()) {
    $cols = @()
    for ($i = 0; $i -lt $reader.FieldCount; $i++) {
        $val = [string]$reader[$i]
        $cols += $val
    }
    $nonEmpty = ($cols | Where-Object { $_ -ne "" }).Count
    if ($nonEmpty -gt 0) {
        Write-Output "R$($rowNum): $($cols -join ' | ')"
    }
    $rowNum++
    if ($rowNum -ge 2000) { break }
}
$reader.Close()

# ECU INFO 시트
Write-Output ""
Write-Output "=========================================="
Write-Output "SHEET: ECU INFO - 전체"
Write-Output "=========================================="
try {
    $cmd2 = $conn.CreateCommand()
    # 시트명에 한글이 있으니 스키마에서 직접 가져오기
    $schema = $conn.GetOleDbSchemaTable([System.Data.OleDb.OleDbSchemaGuid]::Tables, $null)
    $ecuSheet = ""
    foreach ($row in $schema.Rows) {
        $name = $row['TABLE_NAME']
        if ($name -match 'ECU.*INFO' -and $name -match '\$$' -and $name -notmatch '\$_' -and $name -notmatch '\$[A-Z]') {
            $ecuSheet = $name
            break
        }
    }
    if ($ecuSheet -ne "") {
        Write-Output "찾은 시트: $ecuSheet"
        $cmd2.CommandText = "SELECT * FROM [$ecuSheet]"
        $reader2 = $cmd2.ExecuteReader()
        $rowNum2 = 0
        while ($reader2.Read()) {
            $cols = @()
            for ($i = 0; $i -lt $reader2.FieldCount; $i++) { $cols += [string]$reader2[$i] }
            $nonEmpty = ($cols | Where-Object { $_ -ne "" }).Count
            if ($nonEmpty -gt 0) { Write-Output "R$($rowNum2): $($cols -join ' | ')" }
            $rowNum2++
            if ($rowNum2 -ge 200) { break }
        }
        $reader2.Close()
    }
} catch {
    Write-Output "ECU INFO 읽기 오류: $_"
}

$conn.Close()
